#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007

uint64_t fib[100];

uint64_t calculateFib(int n) {
    fib[0] = 0;
    fib[1] = 1;
    for (int i = 2; i <= n; i++) {
        fib[i] = (fib[i-1] + fib[i-2]) % MOD;
    }
    return fib[n];
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        uint64_t N;
        scanf("%llu", &N);
        if(N == 1) {
            printf("2\n");
        } else if(N == 2) {
            printf("6\n");
        } else {
            uint64_t result = (calculateFib(N-1) + calculateFib(N-2)) * 2;
            printf("%llu\n", result % MOD);
        }
    }
    return 0;
}

